module RefModule (  
    input wire clk,  
    input wire rst,  
    input wire [7:0] data_in,  
    output reg [7:0] data_out  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin  
        if (rst)  
            data_out <= 8'b0;  
        else  
            data_out <= data_in >> 1;  
    end  
endmodule
